import{c as a,Q as t,j as o,m as i}from"./chunks/framework.CWuRYD45.js";const u=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{"title":"Privacy Policy","aside":false,"footer":false},"headers":[],"relativePath":"privacy.md","filePath":"privacy.md","lastUpdated":null}'),n={name:"privacy.md"};function r(s,e,l,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="privacy-policy-—-nlpm" tabindex="-1">Privacy Policy — NLPM <a class="header-anchor" href="#privacy-policy-—-nlpm" aria-label="Permalink to &quot;Privacy Policy — NLPM&quot;">​</a></h1><p><em>Last updated: 2026-05-26</em></p><p>NLPM analyzes natural-language artifacts inside your repository — locally. The slash-command surface (<code>/nlpm:*</code>) is delivered as a Claude Code plugin; the scoring rubric covers artifacts authored for Claude Code, Codex CLI, and Antigravity. The standalone Python validator (<code>bin/nlpm-check</code>) runs without Claude Code at all. This policy describes the data NLPM handles.</p><h2 id="what-nlpm-reads" tabindex="-1">What NLPM reads <a class="header-anchor" href="#what-nlpm-reads" aria-label="Permalink to &quot;What NLPM reads&quot;">​</a></h2><p>The contents of files in your project (skills, agents, commands, rules, hooks, manifests) when you run any of: <code>/nlpm:ls</code>, <code>/nlpm:score</code>, <code>/nlpm:check</code>, <code>/nlpm:fix</code>, <code>/nlpm:test</code>, <code>/nlpm:security-scan</code>, <code>/nlpm:trend</code>. Also reads <code>.claude/nlpm.local.md</code> (per-project configuration) when present.</p><h2 id="what-nlpm-writes" tabindex="-1">What NLPM writes <a class="header-anchor" href="#what-nlpm-writes" aria-label="Permalink to &quot;What NLPM writes&quot;">​</a></h2><p><code>.claude/nlpm-history.json</code> — per-project snapshots of scores and component counts over time. Stored on your local filesystem; never transmitted. The standalone validator (<code>bin/nlpm-check</code>) reads and exits without writing.</p><h2 id="what-nlpm-transmits" tabindex="-1">What NLPM transmits <a class="header-anchor" href="#what-nlpm-transmits" aria-label="Permalink to &quot;What NLPM transmits&quot;">​</a></h2><p><strong>Nothing.</strong> All scoring, checking, fixing, and testing runs locally through Claude Code. NLPM does not maintain its own backend, does not phone home, does not collect telemetry, does not register usage with any third party.</p><p>When Claude Code orchestrates the agents (scorer, scanner, checker, etc.), the artifact contents are sent to Anthropic&#39;s API <strong>by Claude Code itself</strong> — under Anthropic&#39;s privacy terms, using your own credentials. NLPM is not in that path.</p><h2 id="third-parties" tabindex="-1">Third parties <a class="header-anchor" href="#third-parties" aria-label="Permalink to &quot;Third parties&quot;">​</a></h2><p>Optional badge fetching from shields.io occurs only if you opt in by embedding the &quot;Validated by NLPM&quot; badge URL in your README. shields.io&#39;s privacy policy applies in that case.</p><h2 id="what-about-the-auditor-pipeline" tabindex="-1">What about the auditor pipeline? <a class="header-anchor" href="#what-about-the-auditor-pipeline" aria-label="Permalink to &quot;What about the auditor pipeline?&quot;">​</a></h2><p>The <code>auditor/</code> directory inside the NLPM source repo runs a separate GitHub Actions pipeline that audits <strong>other</strong> public plugin and skill repositories (today: Claude Code plugins; Codex CLI and Antigravity discovery is planned). That pipeline runs on the maintainer&#39;s GitHub account, not on your machine. Installing NLPM as a plugin does <strong>not</strong> enroll your repository in that pipeline.</p><h2 id="data-deletion" tabindex="-1">Data deletion <a class="header-anchor" href="#data-deletion" aria-label="Permalink to &quot;Data deletion&quot;">​</a></h2><p>There is no centralized data to delete on the maintainer&#39;s side. To remove local data: delete <code>.claude/nlpm-history.json</code> and <code>.claude/nlpm.local.md</code> from your projects, then <code>claude plugin uninstall nlpm@xiaolai</code>.</p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><p>For privacy questions or to report a discrepancy with this policy: <strong><a href="mailto:xiaolaiapple@gmail.com" target="_blank" rel="noreferrer">xiaolaiapple@gmail.com</a></strong>.</p>',18)])])}const m=a(n,[["render",r]]);export{u as __pageData,m as default};
